row.arkime:
ip.src == $MPNET
&& protocols == [tls && http]
&& http.user-agent == "*Mozilla*"
&& tls.ja3 != $BROWSER_JA3_RANGE
// JA3 covers most known-malicious implant fingerprints. See Suricata column for
// JA4 if your sensor supports it.

row.suricata:
alert tls $HOME_NET any
  -> $EXTERNAL_NET 443
  (msg:"TA0011 T1573 JA4 / UA
    mismatch claimed browser TLS
    fingerprint inconsistent";
  flow:established,to_server;
  ja3.hash;
  classtype:trojan-activity;
  sid:9157303; rev:1;)

alert http $HOME_NET any
  -> $EXTERNAL_NET any
  (msg:"TA0011 T1071.001 HTTP
    beacon Cobalt Strike default
    profile URI";
  flow:established,to_server;
  content:"GET"; http.method;
  pcre:"/^\/(ca|dpixel|fwlink|
    pixel|__utm\.gif|
    jquery-3\.3\.1\.min\.js|
    load|api\/x)(\?|$)/i";
  http.uri;
  threshold:type both,
    track by_src,
    count 5, seconds 3600;
  classtype:trojan-activity;
  sid:9107101; rev:1;)

alert udp $HOME_NET any
  -> $NETWORK_DEVICES 161
  (msg:"TA0009 T1602.002 SNMP
    CISCO-CONFIG-COPY-MIB walk
    config dump";
  content:"|2b 06 01 04 01 09 09 60|";
  classtype:trojan-activity;
  sid:9160202; rev:1;)

alert tcp $HOME_NET any
  -> $HOME_NET 445
  (msg:"TA0006 T1003.001 SMB write
    of memory dump file LSASS
    exfiltration";
  flow:established,to_server;
  pcre:"/(lsass\.dmp|memory\.dmp|
    \.dmp)/i";
  classtype:trojan-activity;
  sid:9100301; rev:1;)

alert dns $HOME_NET any
  -> any 53
  (msg:"TA0007 T1018 Reverse DNS
    PTR query burst internal
    host enumeration";
  flow:stateless;
  dns.query;
  pcre:"/in-addr\.arpa$/";
  threshold:type both,
    track by_src,
    count 50, seconds 300;
  classtype:attempted-recon;
  sid:9101804; rev:1;)

alert udp $HOME_NET any
  -> any 53
  (msg:"TA0010 T1041 DNS tunneling
    exfil high subdomain unique
    count single parent domain";
  content:"|01 00 00 01|"; depth:8;
  threshold:type both,
    track by_src,
    count 100, seconds 600;
  classtype:trojan-activity;
  sid:9104102; rev:1;)

alert tcp $HOME_NET any
  -> $EXTERNAL_NET 21
  (msg:"TA0011 T1071.002 Outbound
    FTP from non-file-server host
    possible C2";
  flow:established,to_server;
  content:"USER "; depth:5;
  classtype:trojan-activity;
  sid:9107105; rev:1;)

alert tcp $HOME_NET any
  -> $EXCHANGE_HOSTS 443
  (msg:"TA0009 T1114.002 EWS bulk
    item enumeration email
    collection burst";
  flow:established,to_server;
  content:"/EWS/Exchange.asmx";
  http_uri;
  pcre:"/(<m:FindItem|<m:GetItem|
    <t:ExportItems)/i";
  threshold:type both,
    track by_src,
    count 100, seconds 600;
  classtype:trojan-activity;
  sid:9111402; rev:1;)

alert tcp $HOME_NET any
