  (msg:"TA0007 T1018 NetBIOS NBNS
    name service query burst
    host enumeration";
  flow:to_server;
  threshold:type both,
    track by_src,
    count 30, seconds 60;
  classtype:attempted-recon;
  sid:9101803; rev:1;)

alert tls $HOME_NET any
